CREATE TABLE IF NOT EXISTS products (
  sku TEXT PRIMARY KEY,
  name TEXT NOT NULL,
  description TEXT,
  price REAL NOT NULL,
  compare_price REAL,
  category TEXT,
  stock INTEGER DEFAULT 50,
  image_url TEXT,
  images TEXT,
  is_active INTEGER DEFAULT 1,
  is_featured INTEGER DEFAULT 0,
  track_inventory INTEGER DEFAULT 1,
  tags TEXT DEFAULT '[]',
  website_link TEXT,
  material TEXT,
  created_at TEXT DEFAULT (datetime('now')),
  updated_at TEXT DEFAULT (datetime('now'))
);

-- Products import
INSERT OR REPLACE INTO products (sku, name, description, price, compare_price, category, stock, image_url, images, is_active, is_featured, track_inventory, tags, website_link, material)
VALUES ('201002', 'Clover & Flower Bracelet - Artificial Yellow Gold', 'This elegant bangle bracelet, crafted in artificial yellow gold, features a delicate openwork design with two prominent floral elements. A larger, stylized four-leaf clover and a smaller flower-like charm with a dark center adorn the band. Sparkling clear stones are set along the edges of the bangle, adding a touch of subtle glamour. The bracelet is beautifully presented on a marble-patterned surface, highlighting its refined and feminine aesthetic.Size: .Free shipping on orders over 498/- Happy shopping!.Free Size upto 2.6 Size.', 499, 999, 'bracelet', 50, 'https://www.kaapav.com/web/image/product.template/480/image_128?unique=1745829328000', '["https://www.kaapav.com/web/image/product.template/480/image_128?unique=1745829328000","https://www.kaapav.com/web/image/product.image/12/image_1920?unique=1744734653000","https://www.kaapav.com/web/image/product.image/13/image_1920?unique=1744734653000"]', 1, 0, 1, '[]', 'https://www.kaapav.com/shop/0201002-clover-flower-bracelet-artificial-yellow-gold-480', 'Anti-Tarnish Artificial Jewellery');
INSERT OR REPLACE INTO products (sku, name, description, price, compare_price, category, stock, image_url, images, is_active, is_featured, track_inventory, tags, website_link, material)
VALUES ('201007', 'Wave Pattern Hinged Bracelet - Artificial Yellow Gold', 'This elegant bracelet showcases a unique series of textured wave motifs, crafted with a matte finish that adds depth and sophistication to the design. The curved shapes are neatly aligned along the center of the bangle, creating a rhythmic flow that evokes the serenity of ocean waves. A small embedded stone at the end adds a subtle sparkle. The bracelet is hinged for easy wear and is beautifully finished in artificial yellow gold, offering a luxurious yet modern aesthetic perfect for both casual and formal settings.Size: Free Size upto 2.6 Size.Free shipping on orders over 498/- Happy shopping!', 499, 999, 'bracelet', 50, 'https://www.kaapav.com/web/image/product.image/363/image_1920?unique=1758955694000', '["https://www.kaapav.com/web/image/product.image/363/image_1920?unique=1758955694000","https://www.kaapav.com/web/image/product.image/28/image_1920?unique=1744736136000","https://www.kaapav.com/web/image/product.image/29/image_1920?unique=1758955713000"]', 1, 0, 1, '[]', 'https://www.kaapav.com/shop/0201007-wave-pattern-hinged-bracelet-artificial-yellow-gold-485', 'Anti-Tarnish Artificial Jewellery');
INSERT OR REPLACE INTO products (sku, name, description, price, compare_price, category, stock, image_url, images, is_active, is_featured, track_inventory, tags, website_link, material)
VALUES ('201008', 'Malachite & Crystal Accent Bracelet-Artificial Yellow Gold', 'This elegant bracelet, crafted in artificial yellow gold, features a striking central oval inlaid with vibrant green malachite-style stripes and subtle Roman numeral markings. Flanking the central piece are openwork circular elements, each accented with a sparkling clear crystal. Additional crystals are embedded along the bangle, creating a sophisticated and eye-catching design. The bracelet is displayed on a marble surface, enhancing its luxurious appeal. Size: Free Size upto 2.6 Size.', 499, 999, 'bracelet', 50, 'https://www.kaapav.com/web/image/product.template/486/image_128?unique=1745829380000', '["https://www.kaapav.com/web/image/product.template/486/image_128?unique=1745829380000","https://www.kaapav.com/web/image/product.image/36/image_1920?unique=1744782040000","https://www.kaapav.com/web/image/product.image/37/image_1920?unique=1744782040000"]', 1, 0, 1, '[]', 'https://www.kaapav.com/shop/0201008-malachite-crystal-accent-bracelet-artificial-yellow-gold-486?page=2&category=13', 'Anti-Tarnish Artificial Jewellery');
INSERT OR REPLACE INTO products (sku, name, description, price, compare_price, category, stock, image_url, images, is_active, is_featured, track_inventory, tags, website_link, material)
VALUES ('201010', 'Iconic Stripe Bangle Bracelet -Artificial Yellow Gold', 'Infused with bold elegance, this bracelet features a striking circular design with signature red and green enamel stripes. Sparkling stones and a sleek yellow gold finish make it a standout piece for any outfit. Modern yet timelessperfect for those who love luxury with a pop of personality.Free Size upto 2.6 Size.Free shipping on orders over 498/- Happy shopping!', 499, 999, 'bracelet', 50, 'https://www.kaapav.com/web/image/product.template/488/image_128?unique=1745829387000', '["https://www.kaapav.com/web/image/product.template/488/image_128?unique=1745829387000","https://www.kaapav.com/web/image/product.image/44/image_1920?unique=1744782479000","https://www.kaapav.com/web/image/product.image/45/image_1920?unique=1744782479000"]', 1, 0, 1, '[]', 'https://www.kaapav.com/shop/0201010-iconic-stripe-bangle-bracelet-artificial-yellow-gold-488', 'Anti-Tarnish Artificial Jewellery');
INSERT OR REPLACE INTO products (sku, name, description, price, compare_price, category, stock, image_url, images, is_active, is_featured, track_inventory, tags, website_link, material)
VALUES ('201011', 'Heart & Initial Sparkle Bracelet -Artificial Yellow Gold', 'Make a bold statement of love and elegance with this stunning bracelet, featuring T?Co. initials adorned with a heart-shaped gemstone. Twin rows of dazzling stones on each side add a luxurious sparkle that catches every eye. Crafted in radiant artificial yellow gold, its the perfect gift for someone truly specialor yourself.Free Size upto 2.6 Size.Free shipping on orders over 498/- Happy shopping!', 499, 999, 'bracelet', 50, 'https://www.kaapav.com/web/image/product.template/489/image_128?unique=1744782998000', '["https://www.kaapav.com/web/image/product.template/489/image_128?unique=1744782998000","https://www.kaapav.com/web/image/product.image/48/image_1920?unique=1744782998000","https://www.kaapav.com/web/image/product.image/49/image_1920?unique=1744782998000"]', 1, 0, 1, '[]', 'https://www.kaapav.com/shop/0201011-heart-initial-sparkle-bracelet-artificial-yellow-gold-489', 'Anti-Tarnish Artificial Jewellery');
INSERT OR REPLACE INTO products (sku, name, description, price, compare_price, category, stock, image_url, images, is_active, is_featured, track_inventory, tags, website_link, material)
VALUES ('201012', 'Evil Eye & Tree of Life Bangle - Artificial Yellow Gold', 'This unique bangle, crafted in artificial yellow gold, features a central evil eye charm with a detailed tree of life design within the iris. Sparkling clear stones accent the edges of the bangle, while vibrant blue stones are incorporated on either side of the central motif, adding a pop of color and symbolic meaning. The bracelet is elegantly displayed on a marble surface, highlighting its intricate and protective design.Free Size upto 2.6 Size.Free shipping on orders over 498/- Happy shopping!', 499, 999, 'bracelet', 50, 'https://www.kaapav.com/web/image/product.template/490/image_128?unique=1745307651000', '["https://www.kaapav.com/web/image/product.template/490/image_128?unique=1745307651000","https://www.kaapav.com/web/image/product.image/52/image_1920?unique=1744783317000","https://www.kaapav.com/web/image/product.image/53/image_1920?unique=1744783317000"]', 1, 0, 1, '[]', 'https://www.kaapav.com/shop/0201012-evil-eye-tree-of-life-bangle-artificial-yellow-gold-490', 'Anti-Tarnish Artificial Jewellery');
